      ((fr.labor?.plasterOuter || 0) + (fr.labor?.plasterInner || 0) + (fr.labor?.plasterCeiling || 0)) * n(flab[2]?.price || '0') +
        ((fr.labor?.paintWalls || 0) + (fr.labor?.paintCeiling || 0)) * n(flab[3]?.price || '0') +
          ((fr.labor?.tileFloor || 0) + (fr.labor?.tileBath || 0) + (fr.labor?.tileKitchen || 0)) * n(flab[4]?.price || '0');  
          const fext = finishesPrices.finishesExtra || [];
const feCost = 
  (fr.extras?.bathrooms || 0) * n(fext[0]?.price || '0') +
    (fr.extras?.kitchens || 0) * n(fext[1]?.price || '0') +
      (fr.extras?.windows || 0) * n(fext[2]?.price || '0') +
        (fr.extras?.windows || 0) * n(fext[4]?.price || '0') +
          (fr.extras?.doors || 0) * n(fext[5]?.price || '0');                                                                                                  const rate = n(settings.rate) || 1;
                                                                                                      const floors = n(settings.floors) || 1;
                                                                                                        const cv = (v: number) => settings.currency === 'YER' ? v : v / rate;

                                                                                                          // قراءة البيانات
                                                                                                            const prices = G('prices') || { steelMode: 'separate', steelUnified: '3500', steelPrices: {}, concrete: [], preliminary: [], block: [], labor: [], other: [] };
